mapper.select:
SELECT T.SEQ, T.AFFIRM_TYPE, T.AFFIRM_TYPE_NAME, T.APPLY_NO, T.APPLY_TYPE, T.APPLY_FLAG, T.APPLY_PERSON_ID, T.AFFIRM_PERSON_ID, T.TITLE, T.AFFIRM_LEVEL, T.AFFIRM_FLAG, T.AFFIRM_URL, T.APPLY_TYPE_CODE, T.APPLY_PERSON_INFO, T.ACTIVITY, T.AFFIRM_FLAG_NAME, T.AFFIRM_NAME, T.DEPTNAME, T.APPLY_AFFIRM_FLAG_NO, T.APPLY_AFFIRM_FLAG, T.UPDATE_DATE, T.AFFIRM_CONTENT FROM ( SELECT A.SEQ, A.AFFIRM_TYPE, DECODE(A.AFFIRM_TYPE, '1', '审核', '2', '协议', '3', '通告', '4', '企案', '审核') AS AFFIRM_TYPE_NAME, A.APPLY_NO, A.APPLY_TYPE, A.APPLY_FLAG, A.APPLY_PERSON_ID, A.AFFIRM_PERSON_ID, A.TITLE, TO_CHAR(A.AFFIRM_LEVEL) AS AFFIRM_LEVEL, A.AFFIRM_FLAG, A.AFFIRM_URL, A.APPLY_TYPE_CODE, A.APPLY_PERSON_INFO, A.ACTIVITY, DECODE( A.AFFIRM_TYPE, '3', DECODE(A.AFFIRM_FLAG, '0', '未通告', '已通告'), '4', DECODE(A.AFFIRM_FLAG, '2', '取消', '提交'), DECODE(A.AFFIRM_FLAG, '0', '未审批', '1', '已通过', '已否决') ) AS AFFIRM_FLAG_NAME, HR.LOCAL_NAME || '/' || GET_CODE_NAME(HR.POST_GRADE_NO, #{lang, jdbcType=VARCHAR}) AS AFFIRM_NAME, GET_DEPT_NAME(HR.DEPTNO, #{lang, jdbcType=VARCHAR}) AS DEPTNAME, A.APPLY_AFFIRM_FLAG AS APPLY_AFFIRM_FLAG_NO, GET_CODE_NAME(A.APPLY_AFFIRM_FLAG, #{lang, jdbcType=VARCHAR}) AS APPLY_AFFIRM_FLAG, TO_CHAR(A.AFFIRM_DATE, 'DD/MM/YYYY HH24:MI:SS') AS UPDATE_DATE, A.AFFIRM_CONTENT FROM SY_AFFIRM_EMAIL A INNER JOIN HR_EMPLOYEE HR ON A.AFFIRM_PERSON_ID = HR.PERSON_ID WHERE TO_CHAR(A.APPLY_NO) = #{applyNo, jdbcType=VARCHAR}
AND A.APPLY_TYPE = #{applyType, jdbcType=VARCHAR}
AND A.APPLY_AFFIRM_FLAG <> '14014310' UNION ALL SELECT '' AS SEQ, '' AS AFFIRM_TYPE, '' AS AFFIRM_TYPE_NAME, TO_CHAR(B.APPLY_NO) AS APPLY_NO, '' AS APPLY_TYPE, '' AS APPLY_FLAG, '' AS APPLY_PERSON_ID, '' AS AFFIRM_PERSON_ID, '' AS TITLE, '100' AS AFFIRM_LEVEL, TO_CHAR(B.CONFIRM_FLAG) AS AFFIRM_FLAG, '' AS AFFIRM_URL, '' AS APPLY_TYPE_CODE, '' AS APPLY_PERSON_INFO, '' AS ACTIVITY, '' AS AFFIRM_FLAG_NAME, GET_LOCAL_NAME_BY_PERSONID(B.CONFIRM_BY, #{lang, jdbcType=VARCHAR}) AS AFFIRM_NAME, 'HR' AS DEPTNAME, '' AS APPLY_AFFIRM_FLAG_NO, '' AS APPLY_AFFIRM_FLAG, TO_CHAR(B.CONFIRM_DATE, 'DD/MM/YYYY HH24:MI:SS') AS UPDATE_DATE, B.HR_COMMENT AS AFFIRM_CONTENT FROM ESS_LEAVE_APPLY_TB B WHERE TO_CHAR(B.APPLY_NO) = #{applyNo, jdbcType=VARCHAR} ) T ORDER BY TO_NUMBER(T.AFFIRM_LEVEL)

